import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"爱心便当盒","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/爱心便当盒 .md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/爱心便当盒 .md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/爱心便当盒 .md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"爱心便当盒",tabindex:"-1"},[s("爱心便当盒 "),e("a",{class:"header-anchor",href:"#爱心便当盒","aria-label":'Permalink to "爱心便当盒"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="爱心便当盒-1" tabindex="-1">爱心便当盒 <a class="header-anchor" href="#爱心便当盒-1" aria-label="Permalink to &quot;爱心便当盒&quot;">​</a></h1><p>爱心便当盒<br> 奇物<br> 特异本质<br> 20分<br> 一个铁制的三层便当盒，外壳上有着可爱的花花图案，当然购买时可以定制。在购买时会赠送一条包袱巾，用来包裹便当盒，当然花纹也是自选的。<br> 从上往下，第一层盛装米饭、三明治等主食，第二层盛装各式各样的配菜，第三层装着热气腾腾的汤，这样的结构和保温材料制成的外壳能够让食物保持热气腾腾。</p><p>在影片内，每天一到饭点，空空如也的便当盒里就会出现轮回者在这个时候会想要吃的饭，热气腾腾，非常美味，宛如厨子制作时倾注了爱意。如果回到主神空间便当盒就会自动清空，毕竟回到家就没有带便当的必要了。</p><p>但，如果你在影片里一直不吃掉刷新出来的饭菜的话，便当盒里的饭菜是不会自己消失的，会在里面腐烂发臭，就算扔掉了也不会出现新的食物。<br> 换句话说<br> 你不全部吃掉的话！就不会给你新的了！</p><p>所以一定要好好吃饭哦~~<br> 注：便当是灌注了爱的存在，但食材还是普通的，不要想着海魔眼珠刺身便当什么的（盯）</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
